import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { LoginComponent } from './components/login/login.component';
import { RegisterComponent } from './components/register/register.component';
import { HomeComponent } from './components/home/home.component';
import { ElectionDetailComponent } from './components/election-detail/election-detail.component';
import { AuthGuard } from './guards/auth.guard';
import { CreateElectionComponent } from './components/create-election/create-election.component';
import { ReactiveFormsModule } from '@angular/forms';
import { BrowserModule } from '@angular/platform-browser';

const routes: Routes = [
  { path: 'login', component: LoginComponent },
  { path: 'register', component: RegisterComponent },
  { path: '', component: HomeComponent, canActivate: [AuthGuard] },
  { path: 'elections/:id', component: ElectionDetailComponent, canActivate: [AuthGuard] },
  { path: '/admin/elections/create', component: CreateElectionComponent},
  { path: '**', redirectTo: '' }
];

@NgModule({
  imports: 
  [ 
    RouterModule.forRoot(routes),
    BrowserModule,
    ReactiveFormsModule
  ],
  exports: [RouterModule]
})
export class AppRoutingModule { }
